mapper.select:
SELECT STORE_ID
FROM PURCHASE_ORDERS
WHERE PURCHASE_ORDER_ID = #{purchaseOrderId}

SELECT SI.CURRENT_QUANTITY
FROM STORE_INVENTORIES SI
JOIN PURCHASE_ORDER_ITEMS POI
  ON SI.MATERIAL_ID = POI.MATERIAL_ID
WHERE SI.STORE_ID = #{storeId}
  AND POI.PURCHASE_ORDER_ITEM_ID = #{purchaseOrderItemId}

mapper.update:
UPDATE STORE_INVENTORIES SI
SET SI.CURRENT_QUANTITY = SI.CURRENT_QUANTITY + #{receivedQuantity},
    SI.UPDATED_AT = SYSDATE
WHERE SI.STORE_ID = #{storeId}
  AND SI.MATERIAL_ID = (
      SELECT MATERIAL_ID
      FROM PURCHASE_ORDER_ITEMS
      WHERE PURCHASE_ORDER_ITEM_ID = #{purchaseOrderItemId}
  )

mapper.select:
SELECT SI.STORE_INVENTORY_ID
FROM STORE_INVENTORIES SI
JOIN PURCHASE_ORDER_ITEMS POI
  ON SI.MATERIAL_ID = POI.MATERIAL_ID
WHERE SI.STORE_ID = #{storeId}
  AND POI.PURCHASE_ORDER_ITEM_ID = #{purchaseOrderItemId}
